import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class PathTraversalFixed {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";
        String basePath = "/home/user/public/";

        try {
            // Normalize the user input path and resolve it against the base path
            String normalizedPath = Paths.get(basePath).resolve(Paths.get(userInput)).normalize().toString();

            // Check if the normalized path still starts with the base path
            if (!normalizedPath.startsWith(basePath)) {
                throw new SecurityException("Invalid file path");
            }

            File file = new File(normalizedPath);

            FileInputStream fis = new FileInputStream(file);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } catch (IOException | SecurityException e) {
            e.printStackTrace();
        }
    }
}

